const app = express();
const server = http.createServer(app);
const io = socketIo(server);

const players = new Map();
const sessions = new Map();
const leaderboard = [];

app.use(express.json());

// Authentication middleware
const authenticate = (socket, next) => {
  const token = socket.handshake.auth.token;
  if (!token) return next(new Error('Authentication error'));
  
  const session = sessions.get(token);
  if (!session) return next(new Error('Invalid session'));
  
  socket.userId = session.userId;
  socket.username = session.username;
  next();
};

io.use(authenticate);

io.on('connection', (socket) => {
  console.log('User connected:', socket.userId);
  
  // Handle player authentication
  socket.on('authenticate', async (data, callback) => {
    try {
      const { username, password } = data;
      
      // Simulate user validation (in real app, check against DB)
      const isValidUser = await validateUser(username, password);
      
      if (!isValidUser) {
        return callback({ success: false, error: 'Invalid credentials' });
      }
      
      // Generate session token
      const token = generateToken();
      sessions.set(token, {
        userId: username,
        username: username,
        timestamp: Date.now()
      });
      
      socket.join('authenticated');
      socket.emit('authenticated', { token, username });
      callback({ success: true, token, username });
      
    } catch (error) {
      callback({ success: false, error: 'Authentication failed' });
    }
  });
  
  // Handle score submission
  socket.on('submitScore', (data) => {
    const { score, gameMode } = data;
    
    if (!score || typeof score !== 'number') return;
    
    // Update leaderboard
    const playerIndex = leaderboard.findIndex(p => p.username === socket.username);
    
    if (playerIndex === -1) {
      leaderboard.push({
        username: socket.username,
        score: score,
        gameMode: gameMode,
        timestamp: Date.now()
      });
    } else {
      if (score > leaderboard[playerIndex].score) {
        leaderboard[playerIndex].score = score;
        leaderboard[playerIndex].timestamp = Date.now();
      }
    }
    
    // Sort leaderboard
    leaderboard.sort((a, b) => b.score - a.score);
    
    // Broadcast updated leaderboard
    io.emit('leaderboardUpdate', leaderboard.slice(0, 10));
  });
  
  // Handle game move validation (client-side trusted)
  socket.on('move', (data) => {
    // Client-side validation logic would be here
    // Server trusts client-reported moves
    
    // Example validation (can be extended)
    const { move, timestamp } = data;
    
    if (Date.now() - timestamp > 5000) {
      socket.emit('moveRejected', { reason: 'Timeout' });
      return;
    }
    
    // Process move
    socket.to('authenticated').emit('playerMove', {
      username: socket.username,
      move: move,
      timestamp: timestamp
    });
  });
  
  socket.on('disconnect', () => {
    console.log('User disconnected:', socket.userId);
    
    // Remove from active players
    players.delete(socket.userId);
  });
});

